{
  "name": "Alabama Medicare Savings Programs (QMB, SLMB, QI)",
  "eligibility": {
    "age": 65,
    "income_limits": "2026 federal limits apply statewide (Alabama follows federal MSP standards): QMB: Individual $1,350/month, Couple $1,824/month (100% FPL); SLMB: Individual up to approx. $1,620/month (120% FPL), Couple up to approx. $2,189/month; QI: Individual up to approx. $1,850/month (135% FPL), Couple up to approx. $2,500/month. Exact limits increase annually; check current via SSA or Medicaid. Varies by household size per federal poverty guidelines (e.g., adds ~$500/person beyond couple).[5][2]",
    "asset_limits": "2026: Individual $9,950; Couple $14,910 (exempt: home/land, 1 car, burial plots/funds up to $1,500/person, life insurance up to $1,500 face value, household goods; countable: bank accounts, stocks, bonds, second vehicles/properties).[5][3]",
    "other_requirements": ["Must be enrolled in Medicare Parts A and B (or eligible for Part A)", "U.S. citizen or qualified immigrant", "Alabama resident", "Not eligible for full Medicaid (QI cannot overlap with other Medicaid)", "QI requires prior-year recipients get priority; first-come, first-served with limited funding"]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Pays Medicare Part A premium (if applicable), Part B premium (~$185/month in 2026), deductibles, coinsurance/copayments (providers cannot bill beneficiary for Medicare-covered services); auto-qualifies for Extra Help (Part D low-income subsidy, caps drug copays at $12.65/drug). SLMB: Pays Part B premium only. QI: Pays Part B premium only (no Medicaid card).[1][5][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: medicaid.alabama.gov (MEDICAID application portal)", "Phone: 1-800-362-1504 (Alabama Medicaid)", "Mail/In-person: Local Medicaid District Offices (find via medicaid.alabama.gov/content/2.0_Contact/2.1_District_Offices.aspx)", "Download Form: Medicaid Application (Form MG-14-MA or online equivalent)"],
    "processing_time": "QMB: Active month after approval; SLMB/QI: Active month of application, retroactive up to 3 months prior if eligible.[1][6]",
    "waitlist": "QI only: Limited funding; first-come, first-served, priority to prior recipients; may close when funds exhausted.[6]",
    "forms": ["MEDICAID Application (online or MG-14-MA)", "MSP-specific via same form"],
    "documents": ["Proof of income (SSI award, pay stubs, pension statements)", "Proof of resources (bank statements, deeds)", "Medicare card", "ID (SSN, birth certificate)", "Proof of residency", "Immigration docs if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Alabama Medicare residents",
    "regional_variations": "Processing may vary by local Medicaid district office workload, but eligibility/benefits uniform.[6]",
    "offices_or_providers": ["Local Medicaid District Offices statewide (e.g., Birmingham, Mobile, etc., listed on medicaid.alabama.gov)"]
  },
  "official_source": "https://medicaid.alabama.gov/content/3.0_Apply/3.2_Qualifying/3.2.6_Help_Paying_Medicare.aspx",
  "gotchas": ["QI funding limited—apply early in year; no Medicaid card for SLMB/QI (QMB gets one); providers must accept Medicaid assignment for QMB (cannot bill you); auto-Extra Help but must confirm enrollment; income/asset limits exclude some deductions (e.g., $20 disregard); cannot overlap QI with other Medicaid; retroactive coverage for SLMB/QI but not QMB; limits update yearly—use 2026 figures above but verify.[1][5][6]", "QMB protections: Report bills for Medicare services (illegal to charge)."],
  "data_shape_notes": "Tiered by income (QMB lowest, then SLMB, QI highest); QI capped funding/annual reapply; uniform statewide but district processing; scales by household size via FPL; auto-LIS linkage."
}

{
  "name": "Alabama Meals on Wheels (Elderly Nutrition Program)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or restrictions[2][6]",
    "asset_limits": "No asset limits mentioned; not applicable[2][6]",
    "other_requirements": ["Homebound or unable to shop/prepare meals without assistance (for delivery)[1][2][6][8]", "Live in service area/county[1][2][6]", "Spouse of eligible participant (any age)[5][6][8]", "Person with disability residing with eligible participant[5][6][8]", "Person with disability under 60 in housing where ENP is provided[5][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritious hot or frozen meals providing at least 1/3 of daily dietary reference intakes per meal; delivered to homebound seniors or served at senior centers; no charge for meals, voluntary contributions accepted[6]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) by phone or visit senior center[1][6][8]", "Jefferson County example: Contact Meals on Wheels Jefferson County or United Way Area Agency on Aging[2][8]", "No statewide phone or online form specified; use Alabama Age Line for referrals (implied via alabamaageline.gov)[6]"],
    "processing_time": "Not specified; simple enrollment form at senior center on initial visit[8]",
    "waitlist": "Not mentioned; may vary by local provider[1]",
    "forms": ["Simple enrollment form at senior centers[8]", "Application and possible needs assessment by local provider[4]"],
    "documents": ["Dietary restrictions/allergies, emergency contacts, medical issues, prescriptions, adaptive equipment, physician contacts, health insurance, hospitalization history (for some assessments)[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must live in county served by local AAA; not all areas have home delivery[6]",
    "regional_variations": "Managed by local Area Agencies on Aging (AAA) per county; different providers (e.g., Meals on Wheels Jefferson County, United Way Central Alabama); home delivery availability varies; menus vary monthly by region[2][6][8]",
    "offices_or_providers": ["Local Area Agency on Aging offices by county[6]", "Example: United Way Area Agency on Aging (Jefferson County)[8]", "West Alabama Aging Agency[5]"]
  },
  "official_source": "https://alabamaageline.gov/elderly-nutrition-program/",
  "gotchas": ["Not all areas offer home delivery; must confirm with local AAA[6]", "Eligibility varies slightly by provider (e.g., Jefferson County specifies homebound in county)[2]", "Voluntary contributions expected but not required[6]", "Separate from food assistance programs like SNAP which have income/work rules[3]", "Spouses/disabled under 60 only if living with eligible senior[6]"],
  "data_shape_notes": "Decentralized by county via local AAAs; no statewide income test; home delivery not universal; congregate meals more widely available than delivery"
}

{
  "name": "Alabama Legal Services Corporation (Legal Aid for Seniors)",
  "eligibility": {
    "age": 60,
    "income_limits": "Elder grants are not income-based; general LSA services require household income at or below 125% of the 2024 Federal Poverty Guidelines (exact dollar amounts vary annually by household size and are set by U.S. Dept. of Health & Human Services; no specific table provided in sources—call for current figures)",
    "asset_limits": "Personal assets may affect eligibility for some services, but no specific limits or exemptions detailed for elder program",
    "other_requirements": ["Low-income priority for general services (elder grants waive this)", "Civil legal issues only", "Alabama resident"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice, counseling, representation, document preparation, negotiation, research, education, and outreach on issues including elder abuse, guardianship, housing, Medicaid/Medicare, powers of attorney, wills, Social Security, debt collection, consumer issues, income maintenance, advanced directives, health/long-term care access; non-fee-generating; no specific dollar amounts or hours stated",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 1-866-456-3959 (Elder Helpline, Mon-Fri 8:30am-4:30pm); 1-866-785-1798 (Español)", "Online: https://legalservicesalabama.org/apply-for-services/", "Local Area Agency on Aging (AAA)/ADRC: 1-800-AGE-LINE (1-800-243-5463)"],
    "processing_time": "Not specified",
    "waitlist": "Limited staff resources may result in case rejection or referral; no formal waitlist details",
    "forms": ["Online application via https://legalservicesalabama.org/apply-for-services/"],
    "documents": ["Proof of income, household size, age; specific documents not listed—prepare based on legal issue (e.g., bills, IDs)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Alabama residents age 60+",
    "regional_variations": "Five volunteer lawyer programs cover specific counties; referrals to local clinics or organizations possible; contact local AAA/ADRC for region-specific help",
    "offices_or_providers": ["Legal Services Alabama offices statewide; local Area Agencies on Aging (AAA) and Aging & Disability Resource Centers (ADRC)"]
  },
  "official_source": "https://legalservicesalabama.org/elder-law/",
  "gotchas": ["Elder grants are not income-based but still subject to limited resources—cases may be rejected or referred", "Not all civil cases accepted due to staff limits", "General LSA services have 125% FPG income cap (elder grants waive)", "Must specify elder legal issue during intake", "No criminal cases; focus on civil matters"],
  "data_shape_notes": "Elder grants waive income test (unique non-income-based access for 60+); statewide but with county-specific volunteer programs and referrals; priority for seniors among low-income"
}

{
  "name": "Alabama Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "None",
    "asset_limits": "None",
    "other_requirements": ["Must be a resident of a long-term care facility such as nursing home, assisted living facility, specialty care facility, or boarding home (personal care home). Services also available to family, friends, or facility employees on behalf of residents."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigate and resolve complaints about poor patient care, quality of care, facility issues; provide direct client advocacy; conduct routine/quarterly visitations to facilities; mediate between residents/families and staff; protect residents' rights (e.g., dignity, freedom from restraints, grievance voicing, privacy); educate on rights, facility selection, eligibility criteria; identify additional resources; advocate for systemic changes.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 334-242-5753", "In-person: Alabama Office of the State Long-Term Care Ombudsman Program", "Written: Mail complaints to the office", "Statewide helpline: 1-800-AGE-LINE (1-800-243-5463) for regional Area Agency on Aging support"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["No specific forms required; complaints filed by phone, writing, or in person"],
    "documents": ["None required; complainants do not need to give their name; all information confidential"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services for residents of long-term care facilities across Alabama",
    "regional_variations": "Administered statewide by Alabama Department of Senior Services (ADSS) with at least one community ombudsman per Area Agency on Aging planning and service area (13 areas with 20.30 certified ombudsmen total); local agencies handle mediation, education, and visits but follow uniform state standards",
    "offices_or_providers": ["State Office: Alabama Department of Senior Services, Virginia Moore-Bell, Director (334-242-5753)", "Regional: Area Agencies on Aging (e.g., East Alabama Aging, Aging South Alabama)"]
  },
  "official_source": "https://alabamaageline.gov/ombudsman/",
  "gotchas": ["Not a service providing direct care, financial aid, or placement—purely advocacy and complaint resolution; no financial eligibility barriers but limited to long-term care facility residents (not home-based care); confidential but may require facility access for investigation; volunteers essential but must be trained/certified; people miss that anyone (not just residents) can file complaints on behalf of others."],
  "data_shape_notes": "no income/asset/age test; advocacy-only (no direct services or reimbursement); operates via statewide office + regional Area Agencies on Aging; complaint-driven rather than application for benefits"
}
